const c1 = t => (TEAMS[t] && TEAMS[t][1]) || "#39406b", c2 = t => (TEAMS[t] && TEAMS[t][2]) || "#6f7bb0";
function textOn(hex) { const h = hex.replace('#', ''); const r = parseInt(h.slice(0, 2), 16), g = parseInt(h.slice(2, 4), 16), b = parseInt(h.slice(4, 6), 16); return (0.299 * r + 0.587 * g + 0.114 * b) > 150 ? "#0a1020" : "#ffffff"; }

function normSig(x,k,a) {
 return ((x-a)**k)/((x-a)**k+(1-(x-a))**k)
}

/**
 * Calculates the generalized p-mean of an array of numbers.
 * @param {number[]} arr - Array of positive numbers.
 * @param {number} p - The power mean parameter (e.g., -Infinity, 0, 1, 2, Infinity).
 * @returns {number} The generalized p-mean.
 */
function generalizedMean(arr, p = 1) {
    if (!arr || arr.length === 0) return NaN;
    
    const n = arr.length;

    // Edge case: p = Infinity (returns the maximum value)
    if (p === Infinity) {
        return Math.max(...arr);
    }

    // Edge case: p = -Infinity (returns the minimum value)
    if (p === -Infinity) {
        return Math.min(...arr);
    }

    // Edge case: p = 0 (geometric mean)
    if (p === 0) {
        const product = arr.reduce((acc, val) => acc * val, 1);
        return Math.pow(product, 1 / n);
    }

    // Standard p-mean calculation: ( (1/n) * sum(x^p) ) ^ (1/p)
    const sum = arr.reduce((acc, val) => acc + Math.pow(val, p), 0);
    return Math.pow(sum / n, 1 / p);
}

/* ===== SCORING (TUNABLE) ===== */
const RATE = { R0: 0.55, R1: 0.972, gamma: 2.4, Tb: 0.66, GATE: 18 };
const FPPG_FLOOR_PERFECT = 150; /* Total FPPG required for a 17-0 finish. Below this, max is 16-1. */
const CORE = [["P1", "QB"], ["P2", "QB"], ["P3", "QB"]];
const RESULT_ORDER = ["P1","P2","P3"];
const ATKCOEF = 1.030760
const MIDCOEF = 1.025481
const DEFCOEF = 1.028151
/* Each starter's era-relative percentile (erp, 0..1) is baked into the data.
   Team rating = equal-weighted mean of all 7 starters (no position is weighted more).
   Balance gate: the weakest required starter caps the ceiling, so 17-0 needs an
   elite season at EVERY spot. Win curve is non-linear (steep at the top).
   FPPG_FLOOR_PERFECT: an additional raw-points gate for the 17-0 finish. */
function projectRecord(roster) {
    var atkOveralls = []
    var midOveralls = []
    var defOveralls = []
    Object.values(roster).forEach(p => {
        atkOveralls.push(p.atk);
        midOveralls.push(p.mid);
        defOveralls.push(p.def);
    })
    const atkScore = generalizedMean(atkOveralls,3)*ATKCOEF
    const midScore = generalizedMean(midOveralls,3)*MIDCOEF
    const defScore = generalizedMean(defOveralls,3)*DEFCOEF

    const ovrScore = generalizedMean([atkScore,midScore,defScore])
    const points = ovrScore > 97.99 ? 165 : (ovrScore >= 90 ? (65*(165*normSig((ovrScore/100),0.5,-0.02))/37.424550133)-120.425724452 : (ovrScore >= 80 ? (35.8887797754/18.4475182497)*(165*normSig((ovrScore/100),0.2,-0.09))-128.575702638 : (ovrScore >= 70 ? (30/4.45445217992)*(165*normSig((ovrScore/100),0.1,0.64))-444.66159468 : (ovrScore >= 40 ? (20/34.0573143501)*(165*normSig((ovrScore/100),0.3,-0.28))-38.9023002987 : (ovrScore >= 0 ? (15/53.6630250684)*(165*normSig((ovrScore/100),1.8,-0.6))-31.1211420125 : 0)))))
    return [ovrScore, points];
}
function gradeFor(w) {
    if (w > 97.99) return ["S", "The Perfect Season", "#00FFF9"];
    if (w >= 96.5) return ["A+", "Dynasty Roster", "#7CFF71"]; if (w >= 92.5) return ["A", "LAN Champion", "#7CFF71"]; if (w >= 89.5) return ["A-", "Regional #1 Seed", "#7CFF71"];
    if (w >= 86.5) return ["B+", "LAN Contender", "#00D7FF"]; if (w >= 82.5) return ["B", "Regional Contender", "#00D7FF"];if (w >= 79.5) return ["B-", "Regional Top 4", "#00D7FF"];
    if (w >= 76.5) return ["C+", "Major Regular", "#FF7A00"]; if (w >= 72.5) return ["C", "Low-Level LAN Team", "#FF7A00"]; if (w >= 69.5) return ["C-", "LAN Spot Contender", "#FF7A00"];
    if (w >= 66.5) return ["D+", "Regional Top 8", "#FF6482"]; if (w >= 62.5) return ["D", "Regional Top 8 Contender", "#FF6482"]; if (w >= 59.5) return ["D-", "Regional Regular", "#FF6482"];
    if (w >= 56.5) return ["E+", "Consistent Regional Qualifier", "#ce3b3b"]; if (w >= 52.5) return ["E", "Regional Top 12", "#ce3b3b"]; if (w >= 49.5) return ["E-", "Rebuilding Roster", "#ce3b3b"];
    return ["F", "Bubble Team", "#aa3737"];
}

/* const SLOTS = [{ id: "P1", lab: "P1", elig: ["QR"], x: 14, y: 20 }, { id: "P2", lab: "P2", elig: ["QB"], x: 14, y: 35 }, { id: "P3", lab: "P3", elig: ["QB"], x: 14, y: 50 }]; */

const SLOTS = [
    { id: "P1", lab: "P1", elig: ["QB"], x: 0, y: 20 },
{ id: "P2", lab: "P2", elig: ["QB"], x: 0, y: 35 },
{ id: "P3", lab: "P3", elig: ["QB"], x: 0, y: 50 },
]
const CAT_ORDER = ["QB"];
const CAT_SLOTS = { QB: ["P1", "P2", "P3"]};
const CAT_LABEL = { QB: "Confirm"};
const CAT_COLOR = { QB: "var(--qb)"};
function catEligible(pos, cat) { return cat === pos; }

let state;
function reset() { state = { round: 1, roster: {}, spin: null, rrTeam: true, rrYear: true, selected: null, moving: null, moveSource: null, filter: "ALL", sort: "gpg", q: "" }; $("rr-season").disabled = false;}
const $ = id => document.getElementById(id);
const isMobile = () => window.matchMedia("(max-width:760px)").matches;
const YEAR_MIN = 1999;
const teamYears = {"NA": ["S1", "S2", "S3", "S4", "S5", "S6", "S7", "S8", "S9", "SX", "21-22", "22-23", "2024", "2025", "2026"],"EU": ["S1", "S2", "S3", "S4", "S5", "S6", "S7", "S8", "S9", "SX", "21-22", "22-23", "2024", "2025", "2026"]};
Object.keys(teamYears).forEach(t => { if (!teamYears[t].length) delete teamYears[t]; });
const ALL_TEAMS = Object.keys(teamYears), ALL_YEARS = ["S1", "S2", "S3", "S4", "S5", "S6", "S7", "S8", "S9", "SX", "21-22", "22-23", "2024", "2025", "2026"].sort();

function openSlotsLeft() { return SLOTS.filter(s => !state.roster[s.id]); }
function poolFits(key) { const pl = GAMEDATA.pools[key]; if (!pl) return false; const op = new Set(); openSlotsLeft().forEach(s => s.elig.forEach(p => op.add(p))); return pl.some(p => op.has(p.p)); }
function randomSpin(keepTeam, keepYear) {
    let team = keepTeam ? state.spin.team : null, year = keepYear ? state.spin.year : null, tries = 0;
    /* Exclude the currently-shown team/year from re-roll candidates when we're randomizing that dimension. */
    const excludeTeam = (!keepTeam && state.spin) ? state.spin.team : null;
    const excludeYear = (!keepYear && state.spin) ? state.spin.year : null;
    const teamPool = excludeTeam ? ALL_TEAMS.filter(t => t !== excludeTeam) : ALL_TEAMS;
    while (tries++ < 500) {
        const t = team || teamPool[Math.floor(Math.random() * teamPool.length)]; const ysAll = teamYears[t]; const ys = (excludeYear && !keepYear) ? ysAll.filter(y => y !== excludeYear) : ysAll; const ysPick = ys.length ? ys : ysAll; const y = year || ysPick[Math.floor(Math.random() * ysPick.length)];
        if (poolFits(t + "|" + y)) return { team: t, year: y };
    } return { team: team || ALL_TEAMS[0], year: year || teamYears[ALL_TEAMS[0]][0] };
}
function doSpin(keepTeam, keepYear) {
    $("spin-btn").disabled = true; $("reel-team").classList.add("spinning", "lit"); $("reel-year").classList.add("spinning", "lit");
    const target = randomSpin(keepTeam, keepYear); let n = 0;
    const iv = setInterval(() => {
        $("rv-team").textContent = keepTeam ? target.team : ALL_TEAMS[Math.floor(Math.random() * ALL_TEAMS.length)];
        $("rv-year").textContent = keepYear ? target.year : ALL_YEARS[Math.floor(Math.random() * ALL_YEARS.length)];
        if (++n > 12) {
            clearInterval(iv); $("rv-team").textContent = target.team; $("rv-year").textContent = target.year;
            $("reel-team").classList.remove("spinning"); $("reel-year").classList.remove("spinning"); state.spin = target; setTimeout(enterDraft, 1400);
        }
    }, 100);
}
function bannerReset(draft) { $("banner").className = "banner idle"; $("banner").textContent = draft ? "Pick a player to place." : "Roll, then draft a player onto your roster."; }
function showSpinView() {
    $("spin-view").style.display = "flex"; $("draft-view").style.display = "none"; $("context-row").classList.remove("show");
    $("rv-team").textContent = "?"; $("rv-year").textContent = "?"; $("reel-team").classList.remove("lit"); $("reel-year").classList.remove("lit"); $("spin-btn").disabled = false;
    state.selected = null; state.moving = null; bannerReset(false); renderField(); renderRosterBar();
}
function enterDraft() {
    $("spin-view").style.display = "none"; $("draft-view").style.display = "block"; $("context-row").classList.add("show");
    state.selected = null; state.moving = null; $("place-hint").style.display = "none"; bannerReset(true); updateSortOptions(); renderField(); renderRosterBar(); renderPool();
}

function renderField() {
    const f = $("field"); f.querySelectorAll(".pcard.empty").forEach(e => e.remove());
    SLOTS.forEach(s => {
        const fl = state.roster[s.id]; const el = document.createElement("div"); el.className = "pcard empty"; el.dataset.slot = s.id;
        if (fl) {
            el.classList.add("filled");
        const teamID = SZN_SHORT.get(fl.season) + "_" + fl.team
        const imgURL = "/src/165/logos/" + teamID + ".webp"
        const teamCOL = TEAMS.get(teamID)
                var subtext = fl.season + " · " + fl.team
        var allTeams = fl.teams.split(", ")
        for (let i = allTeams.length-1; i>=0; i--) {
            if (allTeams[i] !== fl.team && allTeams[i] !== "") {
                subtext += " · " + allTeams[i]
            }
        }
            el.innerHTML = `<div style="display:flex; width:100%"><div class="pc-icon" style="border: 2px solid ${teamCOL}; background-color:color-mix(in oklab, ${teamCOL} 15%, #0C0C0C 85%)"><img class="pc-image" src="${imgURL}"></div>
        <div style="padding-top: 3px;"><div class="pc-name">${fl.n}</div><div class="pc-sub">${subtext}</div></div><div class="pc-stats">${statsHTML(fl)}</div>`;

            const chip = el.firstChild;
            chip.ondragstart = e => { if (state.selected) { e.preventDefault(); return; } state.moving = s.id; state.selected = null; $("place-hint").style.display = "none"; e.dataTransfer.effectAllowed = "move"; e.dataTransfer.setData("text/plain", s.id); refreshSlots(); $("banner").className = "banner"; $("banner").textContent = `Moving ${fl.n} — drop on a highlighted slot`; };
            chip.ondragend = () => { if (state.moving === s.id) { state.moving = null; refreshSlots(); bannerReset(isDraft()); } };
        }
        else el.innerHTML = `<div style="display:flex; width:100%"><div class="pc-icon" style="visibility:hidden"><img class="pc-image"></div>
        <div style="padding-top: 3px;"><div class="pc-name"></div><div class="pc-sub"></div></div><div class="pc-stats"></div>`;
        el.ondragover = e => { if (state.moving && validDest(state.moving, s.id)) e.preventDefault(); };
        el.ondrop = e => { e.preventDefault(); if (state.moving && validDest(state.moving, s.id)) doMove(state.moving, s.id); };
        f.appendChild(el);
    });
    refreshSlots();
}
function isDraft() { return $("draft-view").style.display === "block"; }
function validDest(fromId, toId) {
    if (fromId === toId) return false; const from = state.roster[fromId]; const toSlot = SLOTS.find(s => s.id === toId);
    if (!state.roster[toId]) return toSlot.elig.includes(from.p);
    const to = state.roster[toId], fromSlot = SLOTS.find(s => s.id === fromId); return toSlot.elig.includes(from.p) && fromSlot.elig.includes(to.p);
}
function doMove(fromId, toId) {
    const from = state.roster[fromId];
    if (!state.roster[toId]) { state.roster[toId] = from; delete state.roster[fromId]; }
    else { const tmp = state.roster[toId]; state.roster[toId] = from; state.roster[fromId] = tmp; }
    state.moving = null; renderField(); renderRosterBar(); bannerReset(isDraft());
}
function startMove(slotId) {
    if (state.moving === slotId) { state.moving = null; refreshSlots(); bannerReset(isDraft()); return; }
    state.moving = slotId; state.selected = null; $("place-hint").style.display = "none"; refreshSlots();
    $("banner").className = "banner"; $("banner").textContent = `Moving ${state.roster[slotId].n} — tap a highlighted slot (or drag)`;
}
function refreshSlots() {
    document.querySelectorAll(".pcard.empty").forEach(el => {
        el.classList.remove("elig", "movedest", "moving"); el.onclick = null; const s = SLOTS.find(x => x.id === el.dataset.slot);
        if (state.selected) { if (!state.roster[s.id] && s.elig.includes(state.selected.p)) { el.classList.add("elig"); el.onclick = () => placePlayer(s.id); } }
        else if (state.moving) { if (s.id === state.moving) { el.classList.add("moving"); el.onclick = () => startMove(s.id); } else if (validDest(state.moving, s.id)) { el.classList.add("movedest"); el.onclick = () => doMove(state.moving, s.id); } }
        else if (state.roster[s.id]) { el.onclick = () => startMove(s.id); }
    });
}
function eligibleSlotExists(p) { return SLOTS.some(s => !state.roster[s.id] && s.elig.includes(p)); }

