    if (p.p === "QB") h = S(p.gpg.toFixed(2), "GOAL/G") + S(p.apg.toFixed(2), "ASST/G", "cut3") + S(p.sapg.toFixed(2), "SAVE/G", "cut2") + S(p.shpg.toFixed(2), "SHOT/G", "cut"); return h;
